375	// expandRepos builds the target repo list from the mutually-exclusive
376	// -repos / -repo-pattern flags. Paths are used verbatim downstream (the
377	// endpoint appends them to the node with no rewriting), so this only validates
378	// and expands {n}; it never rewrites the path shape.
379	func expandRepos(reposCSV, pattern string, count int) ([]string, error) {
380		repos := splitCSV(reposCSV)
381		switch {
382		case len(repos) > 0 && pattern != "":
383			return nil, errors.New("pass -repos or -repo-pattern, not both")
384		case len(repos) > 0:
385			if count > 0 {
386				return nil, errors.New("-repo-count applies to -repo-pattern, not -repos")
387			}
388			return repos, nil
389		case pattern != "":
390			if count <= 0 {
391				return nil, errors.New("-repo-pattern requires -repo-count > 0")
392			}
393			if !strings.Contains(pattern, "{n}") {
394				return nil, errors.New("-repo-pattern must contain the {n} index placeholder (e.g. you/bench-{n})")
395			}
396			for i := 1; i <= count; i++ {
397				repos = append(repos, strings.ReplaceAll(pattern, "{n}", strconv.Itoa(i)))
398			}
399			return repos, nil
400		case count > 0:
401			return nil, errors.New("-repo-count requires -repo-pattern")
402		default:
403			return nil, errors.New("no repos: pass -repos or -repo-pattern + -repo-count")
404		}
405	}
